sql:
SELECT race_id, horse_id, SUM(winnings) AS total_winnings
FROM race_results
GROUP BY race_id, horse_id;

SELECT finish_time
FROM race_results
WHERE race_id = 1 AND finish_pos = '1st';

SELECT training_type
FROM training_history
WHERE horse_id = 0;

SELECT AVG(training_duration) AS average_training_duration
FROM training_history
WHERE horse_id = 0;

external_knowledge:
- The query assumes that a horse's performance is influenced by both its training and medical history; 
- The inclusion of cumulative winnings suggests a focus on long-term success rather than a single event;
- The ranking of horses by total earnings implies a competitive context where overall performance is valued.

sql:
SELECT metric_name, metric_value, metric_date
FROM performance_metrics
WHERE horse_id = 1;

SELECT metric_name
FROM performance_metrics
WHERE horse_id = 0 AND metric_date = '0';

SELECT MAX(metric_value) AS max_metric_value
FROM performance_metrics
WHERE horse_id = 0 AND metric_name = '0';

SELECT horse_id, SUM(winnings) AS total_winnings
FROM horse_racing_history
GROUP BY horse_id;
